pragma cashscript >= 0.13.0;

// Oracle v24-minimal — P01 (R03a) u40 commit widening (closes F-OC12
//   Y2038 PERMANENTLY), kept under the 520-byte P2SH-32 redeem-script cap.
//
// ── The 520-byte wall (why this is "minimal") ────────────────────────
// The Oracle is P2SH-32: when spent, its full redeem script is pushed as a
// single stack item, capped at 520 B by consensus (MAX_SCRIPT_ELEMENT_SIZE).
// redeem = push(tickerLockingBytecode)[36 B] + this body. So this body must
// stay ≤ ~484 B. v24's first cut added P02 length/tokenAmount pins + P01
// Strategy-A caps + F05 restore, reaching a 501-B body → 537-B redeem →
// every Oracle.update failed "stack item exceeds 520 bytes" (caught by a
// libauth VM trace; invisible to cargo + the slot-only standardness gate).
// Those additions are dropped here: they were redundant given the same
// closed-category + vote-pinning invariants documented in PublisherSlot.cash
// and docs/design/minimal-slot-principle.md.
//
//   KEPT: P01 u40 WIDTH (18-B Oracle commit / 18-B slot / 19-B Ticker) — this
//   is the actual F-OC12 Y2038 close (a u32 ts cannot represent wall time
//   after 2038; 5 bytes pushes the horizon to year ~36812). Enforced by the
//   claimedNewTs.length == 5 + claimedMedian.length == 8 gates below, which
//   pin the commit to exactly 18 B.
//
//   DROPPED as redundant (closed-category / self-pinning / vote-pinning):
//   * out[0].tokenAmount == 0  — Oracle is a one-of-a-kind minting NFT; no
//     category fungible tokens can be created.
//   * oldCommit.length == 18   — the Oracle's own re-emit self-pins the commit
//     to 18 B (and genesis mints 18 B); oldCommit is always 18 B.
//   * slotCommit.length == 18  — slots self-pin their 18-B re-emit; closed
//     category means only the 13 legit slots can be inputs.
//   * newTs > prevTs           — implied by `newTs - prevTs >= 60` for the
//     positive bounded values the vote gate admits.
//   * newTs/newSeq < cap       — newTs is vote-pinned to honest-majority real
//     time (a builder can't set it near 2^39 without losing the vote
//     majority); newSeq grows 1/cycle (~1M years to reach 2^39). Both are
//     threshold-absorbed, not load-bearing.
//
// ── v23 wins retained ────────────────────────────────────────────────
//   F01    per-iter slot category pin (V22-OC-22 closure) UNCHANGED
//   T2     activeCount dropped (dead since v15)
//
// All v15..v22 audit-fix gates retained that aren't redundant:
//   F-OC2  tokenAmount pin on both Ticker mints (FT injection prevention)
//   F-OC3  value pin (1500) on both Ticker mints
//   N30    numAttestations <= 13 cap (op-cost insurance)
//   tx.outputs.length <= maxOutputs (token-leak guard)
//
// ── Commitment layouts (v24, widened) ────────────────────────────────
// Oracle (18 B, no version byte, no activeCount):
//   [0..5)    seq                          5 B   u40 LE
//   [5..10)   lastTs                       5 B   u40 LE
//   [10..18)  medianPrice                  8 B   u64 LE
//
// Slot (18 B, no version, no pkh — pkh is in slot LB literal):
//   [0..8)    price                         8 B   u64 LE
//   [8..13)   timestamp                     5 B   u40 LE
//   [13..18)  cycleSeq                      5 B   u40 LE
//
// Ticker (19 B, version 0x80):
//   [0..1)    version                       1 B   0x80
//   [1..6)    cycleSeq                      5 B   u40 LE
//   [6..11)   lastTs                        5 B   u40 LE
//   [11..19)  medianPrice                   8 B   u64 LE

contract Oracle(
    bytes35 tickerLockingBytecode
) {
    function update(
        bytes pricesBlob,
        bytes claimedMedian,
        bytes claimedNewTs,
        bytes budgetPad
    ) {
        require(claimedMedian.length == 8);
        // P01 R03a — newTs widens from 4 B to 5 B (closes F-OC12 Y2038).
        require(claimedNewTs.length == 5);
        // F-OC5 — keep upper bound to block absurd amplification.
        require(budgetPad.length <= 10240);

        int idx = this.activeInputIndex;
        int numAttestations = pricesBlob.length / 8;
        // N30 KEPT — cheap insurance against unbounded op-cost loops.
        require(numAttestations <= 13);

        // ── Self-replicate (Oracle state NFT) ────────────────────────
        require(tx.outputs[0].lockingBytecode == tx.inputs[idx].lockingBytecode);
        require(tx.outputs[0].tokenCategory == tx.inputs[idx].tokenCategory);
        require(tx.outputs[0].value == 2000);

        // ── Read previous Oracle state (18 B v24, no version, no activeCount) ──
        bytes oldCommit = tx.inputs[idx].nftCommitment;
        int prevTs = int(oldCommit.slice(5, 10));
        int newTs  = int(claimedNewTs);
        require(newTs - prevTs >= 60);

        int newSeq = int(oldCommit.slice(0, 5)) + 1;

        // T2 — threshold collapses to constant 7 (activeCount dropped).
        require(numAttestations >= 7);

        // F01 — pin slot inputs to slot category (closes V22-OC-22 quorum
        // bypass). slotCatWithCap = slot_category_reversed (32 B LE wire) ||
        // 0x01 (mutable capability). Build pipeline substitutes this 33-byte
        // literal at deploy time from the slot genesis outpoint.
        bytes slotCatWithCap = 0xBABEFACEBABEFACEBABEFACEBABEFACEBABEFACEBABEFACEBABEFACEBABEFACE01;

        // ── Walk PublisherSlot inputs ────────────────────────────────
        // F01      per-iter slot category gate
        // A3-SORT  pkh-monotonicity is enforced by slot.consume()
        int jitter = 120;
        int lowerVotes = 0;
        int upperVotes = 0;
        int i = 0;
        do {
            int slotIdx = i + 1;
            require(tx.inputs[slotIdx].tokenCategory == slotCatWithCap);
            bytes slotCommit = tx.inputs[slotIdx].nftCommitment;

            // Timestamp votes (median-of-medians, ±jitter window).
            // P01 R03a — slot timestamp widens 4 B → 5 B at offset [8..13).
            int slotTimestamp = int(slotCommit.slice(8, 13));
            if (slotTimestamp + jitter >= newTs) {
                lowerVotes = lowerVotes + 1;
            }
            if (slotTimestamp <= newTs + jitter) {
                upperVotes = upperVotes + 1;
            }

            // Cycle freshness: slot must attest to THIS cycle.
            // P01 R03a — slot cycleSeq widens 4 B → 5 B at offset [13..18).
            require(int(slotCommit.slice(13, 18)) == newSeq);

            // Price matches caller-supplied blob
            require(slotCommit.slice(0, 8) == pricesBlob.slice(i * 8, i * 8 + 8));

            i = i + 1;
        } while (i < numAttestations);
        require(lowerVotes * 2 > numAttestations);
        require(upperVotes * 2 > numAttestations);

        // ── Median position check ────────────────────────────────────
        int medianVal   = int(claimedMedian);
        int actualLower = 0;
        int actualUpper = 0;
        bool foundMedian = false;
        int j = 0;
        do {
            int pVal = int(pricesBlob.slice(j * 8, j * 8 + 8));
            if (pVal < medianVal) {
                actualLower = actualLower + 1;
            } else {
                if (pVal > medianVal) {
                    actualUpper = actualUpper + 1;
                } else {
                    foundMedian = true;
                }
            }
            j = j + 1;
        } while (j < numAttestations);
        require(foundMedian);
        int half = (numAttestations - 1) / 2;
        require(actualLower <= half);
        require(numAttestations - actualUpper > half);

        // ── New Oracle commitment (18 B v24, no version, no activeCount) ──
        // P01 R03a — seqBytes widens 4 B → 5 B, so the assembled commit is
        // 5 + 5 + 8 = 18 B. Ticker commit naturally becomes 1 + 5 + 5 + 8 =
        // 19 B via the same seqBytes + claimedNewTs concatenation below.
        bytes seqBytes        = toPaddedBytes(newSeq, 5);
        bytes newOracleCommit = seqBytes + claimedNewTs + claimedMedian;
        require(tx.outputs[0].nftCommitment == newOracleCommit);

        // ── K=2 Mutable Ticker mints (KEEP F-OC2 tokenAmount pin) ─────
        bytes newTickerCommit = 0x80 + seqBytes + claimedNewTs + claimedMedian;
        bytes tickerCategory  = tx.inputs[idx].tokenCategory.slice(0, 32) + 0x01;

        int k = 0;
        do {
            int tickerIdx = numAttestations + 1 + k;
            require(tx.outputs[tickerIdx].lockingBytecode == tickerLockingBytecode);
            require(tx.outputs[tickerIdx].tokenCategory == tickerCategory);
            require(tx.outputs[tickerIdx].nftCommitment == newTickerCommit);
            require(tx.outputs[tickerIdx].value == 1500);
            require(tx.outputs[tickerIdx].tokenAmount == 0);
            k = k + 1;
        } while (k < 2);

        // ── Output-count cap (token-leak guard, KEEP) ────────────────
        int maxOutputs = numAttestations + 4;
        require(tx.outputs.length <= maxOutputs);
        if (tx.outputs.length == maxOutputs) {
            require(tx.outputs[numAttestations + 3].tokenCategory == 0x);
        }
    }
}
